import{_ as e,o as n,c as a,a2 as l}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"🔗 功率離散供應鏈與競爭分析","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/功率離散元件研究/功率離散供應鏈與競爭分析.md","filePath":"Deep32Q知識庫/產業洞察/功率離散元件研究/功率離散供應鏈與競爭分析.md"}'),s={name:"Deep32Q知識庫/產業洞察/功率離散元件研究/功率離散供應鏈與競爭分析.md"};function i(r,t,d,o,g,p){return n(),a("div",null,[...t[0]||(t[0]=[l(`<h1 id="🔗-功率離散供應鏈與競爭分析" tabindex="-1">🔗 功率離散供應鏈與競爭分析 <a class="header-anchor" href="#🔗-功率離散供應鏈與競爭分析" aria-label="Permalink to &quot;🔗 功率離散供應鏈與競爭分析&quot;">​</a></h1><p><strong>更新日期：</strong> 2026-05-12 <strong>研究範圍：</strong> 供應鏈結構、全球競爭格局、AI 量化影響、關稅戰影響、關鍵風險</p><hr><h2 id="_1-供應鏈結構全景" tabindex="-1">1. 供應鏈結構全景 <a class="header-anchor" href="#_1-供應鏈結構全景" aria-label="Permalink to &quot;1. 供應鏈結構全景&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>功率離散元件完整供應鏈：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌─────────────┐    ┌─────────────┐    ┌──────────────┐    ┌─────────────┐</span></span>
<span class="line"><span>│ 晶圓材料     │    │ 晶圓代工     │    │ 設計/封裝     │    │ 通路/客戶    │</span></span>
<span class="line"><span>│ (矽晶圓/SiC) │───→│ (8吋/12吋)  │───→│ (IDM/Fabless)│───→│ (EMS/Tier-1) │</span></span>
<span class="line"><span>└─────────────┘    └─────────────┘    └──────────────┘    └─────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>晶圓材料供應商：</span></span>
<span class="line"><span>  • 矽晶圓：GlobalWafers (台), Shin-Etsu (日), SUMCO (日)</span></span>
<span class="line"><span>  • SiC襯底：Wolfspeed, Coherent (美), SHM (韓), 漢磊(台), 天科合達(中)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>晶圓代工廠：</span></span>
<span class="line"><span>  • 世界先進 (8926, 台) — SiC 試產線完成</span></span>
<span class="line"><span>  • 漢磊 (8046, 台) — 8吋SiC產線建置中</span></span>
<span class="line"><span>  • TSMC (2330, 台) — SiC 磊晶</span></span>
<span class="line"><span>  • X-FAB (德) — SiC 代工</span></span>
<span class="line"><span>  • 聯電 (2303, 台) — MOSFET 代工</span></span>
<span class="line"><span></span></span>
<span class="line"><span>IDM（設計+製造一貫）：</span></span>
<span class="line"><span>  • 強茂 (2481, 台) — MOSFET + 二極體</span></span>
<span class="line"><span>  • 台半 (5425, 台) — MOSFET + TVS + SiC</span></span>
<span class="line"><span>  • Infineon (德) — 全球功率半導體 #1</span></span>
<span class="line"><span>  • ON Semi (美) — SiC + MOSFET</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Fabless（設計為主）：</span></span>
<span class="line"><span>  • 力智 (6719, 台) — SPS + PMIC</span></span>
<span class="line"><span>  • 富鼎 (8261, 台) — MOSFET + SPS</span></span>
<span class="line"><span>  • 杰力 (5299, 台) — Notebook MOS</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Foundry（純代工）：</span></span>
<span class="line"><span>  • 茂矽 (2342, 台) — MOSFET + SiC 晶圓代工</span></span>
<span class="line"><span></span></span>
<span class="line"><span>通路/客戶：</span></span>
<span class="line"><span>  • EMS五哥（鴻海、廣達、仁寶、緯創、英業達）— AI 伺服器組裝</span></span>
<span class="line"><span>  • 車用 Tier-1（Bosch、Continental、Denso）— EV 動力總成</span></span>
<span class="line"><span>  • CSP（Microsoft, Google, Amazon, Meta）— AI 資料中心</span></span></code></pre></div><hr><h2 id="_2-全球競爭格局" tabindex="-1">2. 全球競爭格局 <a class="header-anchor" href="#_2-全球競爭格局" aria-label="Permalink to &quot;2. 全球競爭格局&quot;">​</a></h2><h3 id="idm-大廠市佔排名-功率半導體整體" tabindex="-1">IDM 大廠市佔排名（功率半導體整體） <a class="header-anchor" href="#idm-大廠市佔排名-功率半導體整體" aria-label="Permalink to &quot;IDM 大廠市佔排名（功率半導體整體）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">排名</th><th style="text-align:left;">公司</th><th style="text-align:center;">國籍</th><th style="text-align:center;">市佔率 (2025)</th><th style="text-align:left;">核心優勢</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>1</strong></td><td style="text-align:left;">Infineon（英飛凌）</td><td style="text-align:center;">德國</td><td style="text-align:center;">~19.5%</td><td style="text-align:left;">功率半導體全球龍頭, SiC/IGBT/MOSFET 全覆蓋</td></tr><tr><td style="text-align:center;"><strong>2</strong></td><td style="text-align:left;">ON Semiconductor（安森美）</td><td style="text-align:center;">美國</td><td style="text-align:center;">~15-18%</td><td style="text-align:left;">SiC MOSFET 領導者, 車用 MOSFET 強項</td></tr><tr><td style="text-align:center;"><strong>3</strong></td><td style="text-align:left;">STMicroelectronics（意法半導體）</td><td style="text-align:center;">瑞士/法</td><td style="text-align:center;">~12-15%</td><td style="text-align:left;">N-Channel MOSFET 強項, 消費電子佈局深</td></tr><tr><td style="text-align:center;"><strong>4</strong></td><td style="text-align:left;">Texas Instruments（德州儀器）</td><td style="text-align:center;">美國</td><td style="text-align:center;">~8-10%</td><td style="text-align:left;">低壓 MOSFET + PMIC 整合, 資料中心應用</td></tr><tr><td style="text-align:center;"><strong>5</strong></td><td style="text-align:left;">Toshiba（東芝）</td><td style="text-align:center;">日本</td><td style="text-align:center;">~5-7%</td><td style="text-align:left;">IGBT + SiC 布局, 工業/車用</td></tr><tr><td style="text-align:center;"><strong>6-10</strong></td><td style="text-align:left;">其他（Rohm, Microchip, Vishay 等）</td><td style="text-align:center;">多國</td><td style="text-align:center;">~30-35%</td><td style="text-align:left;">各領域利基市場</td></tr></tbody></table><blockquote><p><strong>關鍵數字：</strong> Top 5 IDM 合計佔全球功率半導體市場約 <strong>50-55%</strong>。 N-Channel Power MOSFET 市場：Infineon (~18%) + ON Semi + STMicro 合計 &gt;45%。</p></blockquote><h3 id="sic-領導者排名" tabindex="-1">SiC 領導者排名 <a class="header-anchor" href="#sic-領導者排名" aria-label="Permalink to &quot;SiC 領導者排名&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">排名</th><th style="text-align:left;">公司</th><th style="text-align:center;">國籍</th><th style="text-align:left;">核心優勢</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>1</strong></td><td style="text-align:left;">Wolfspeed</td><td style="text-align:center;">美國</td><td style="text-align:left;">SiC 襯底全球最大, 8吋產能領先</td></tr><tr><td style="text-align:center;"><strong>2</strong></td><td style="text-align:left;">STMicroelectronics</td><td style="text-align:center;">瑞士/法</td><td style="text-align:left;">SiC MOSFET + Module 量產</td></tr><tr><td style="text-align:center;"><strong>3</strong></td><td style="text-align:left;">Infineon</td><td style="text-align:center;">德國</td><td style="text-align:left;">SiC Module 車用領先, 1200V/1700V</td></tr><tr><td style="text-align:center;"><strong>4</strong></td><td style="text-align:left;">Rohm（羅姆）</td><td style="text-align:center;">日本</td><td style="text-align:left;">SiC MOSFET 消費電子佈局深</td></tr><tr><td style="text-align:center;"><strong>5</strong></td><td style="text-align:left;">ON Semiconductor</td><td style="text-align:center;">美國</td><td style="text-align:left;">SiC MOSFET 車用放量中</td></tr></tbody></table><h3 id="中國競爭者-大量擴產中" tabindex="-1">中國競爭者（大量擴產中） <a class="header-anchor" href="#中國競爭者-大量擴產中" aria-label="Permalink to &quot;中國競爭者（大量擴產中）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">公司</th><th style="text-align:left;">產品線</th><th style="text-align:left;">規模與進度</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>天科合達</strong></td><td style="text-align:left;">SiC 襯底</td><td style="text-align:left;">中國最大 SiC 襯底供應商, 大量擴產中</td></tr><tr><td style="text-align:left;"><strong>三安光電</strong></td><td style="text-align:left;">SiC IDM</td><td style="text-align:left;">全鏈佈局（襯底→磊晶→製造→封裝）, 大量擴產</td></tr><tr><td style="text-align:left;"><strong>華潤微</strong></td><td style="text-align:left;">MOSFET + IGBT</td><td style="text-align:left;">中國功率半導體 IDM 龍頭之一</td></tr><tr><td style="text-align:left;"><strong>士蘭微</strong></td><td style="text-align:left;">IGBT + SiC Module</td><td style="text-align:left;">中國 IGBT Module 領先, SiC 佈局中</td></tr></tbody></table><hr><h2 id="_3-ai-對功率離散的影響量化" tabindex="-1">3. AI 對功率離散的影響量化 <a class="header-anchor" href="#_3-ai-對功率離散的影響量化" aria-label="Permalink to &quot;3. AI 對功率離散的影響量化&quot;">​</a></h2><h3 id="mosfet-用量對比-傳統-vs-ai-伺服器" tabindex="-1">MOSFET 用量對比：傳統 vs AI 伺服器 <a class="header-anchor" href="#mosfet-用量對比-傳統-vs-ai-伺服器" aria-label="Permalink to &quot;MOSFET 用量對比：傳統 vs AI 伺服器&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:center;">傳統伺服器（單 GPU）</th><th style="text-align:center;">AI 伺服器（8xGPU）</th><th style="text-align:center;">倍數/差異</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>MOSFET 總用量</strong></td><td style="text-align:center;">~30-50 顆</td><td style="text-align:center;">~150-300 顆</td><td style="text-align:center;"><strong>3-6 倍</strong></td></tr><tr><td style="text-align:left;"><strong>GPU 功耗</strong></td><td style="text-align:center;">~300W</td><td style="text-align:center;">~700-1200W+</td><td style="text-align:center;"><strong>2.5-4 倍</strong></td></tr><tr><td style="text-align:left;"><strong>電源轉換級數</strong></td><td style="text-align:center;">2 級</td><td style="text-align:center;">3-4 級（含 48V）</td><td style="text-align:center;"><strong>+50%</strong></td></tr><tr><td style="text-align:left;"><strong>單顆 MOSFET 規格</strong></td><td style="text-align:center;">30V / 50A</td><td style="text-align:center;">100V / 100A+</td><td style="text-align:center;"><strong>3-4 倍</strong></td></tr><tr><td style="text-align:left;"><strong>單顆 MOSFET 價值</strong></td><td style="text-align:center;">基準</td><td style="text-align:center;">2-3 倍</td><td style="text-align:center;">高壓+高頻要求</td></tr></tbody></table><h3 id="ai-伺服器電源架構轉換的深遠影響" tabindex="-1">AI 伺服器電源架構轉換的深遠影響 <a class="header-anchor" href="#ai-伺服器電源架構轉換的深遠影響" aria-label="Permalink to &quot;AI 伺服器電源架構轉換的深遠影響&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>12V → 48V 供電架構轉換（AI 伺服器推動）：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>傳統 12V 架構：</span></span>
<span class="line"><span>AC → PFC (600V Si MOSFET) → 12V DC-DC → VRM (30V MOSFET)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AI 48V 架構：</span></span>
<span class="line"><span>AC → PFC (SiC MOSFET 1200V) → 48V DC-DC (100V MOSFET) → VRM (30-60V MOSFET)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>影響：</span></span>
<span class="line"><span>① PFC 級從 Si MOSFET 升級為 SiC MOSFET（單價提升 5-10 倍）</span></span>
<span class="line"><span>② DC-DC 級從 30V MOSFET 升級為 100V MOSFET（單價提升 2-3 倍）</span></span>
<span class="line"><span>③ 總用量增加 3-6 倍</span></span>
<span class="line"><span>→ 單台 AI 伺服器 MOSFET 總價值提升 10-20 倍</span></span></code></pre></div><h3 id="sps-電源供應模組-整合趨勢" tabindex="-1">SPS（電源供應模組）整合趨勢 <a class="header-anchor" href="#sps-電源供應模組-整合趨勢" aria-label="Permalink to &quot;SPS（電源供應模組）整合趨勢&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">傳統方案</th><th style="text-align:left;">SPS 整合方案</th><th style="text-align:left;">差異</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>元件數量</strong></td><td style="text-align:left;">15-20 顆離散元件</td><td style="text-align:left;">3-5 顆 SPS 模組</td><td style="text-align:left;">減少 70%+</td></tr><tr><td style="text-align:left;"><strong>PCB 空間</strong></td><td style="text-align:left;">大（多元件佔用）</td><td style="text-align:left;">小（整合模組）</td><td style="text-align:left;">節省 50-70%</td></tr><tr><td style="text-align:left;"><strong>單價</strong></td><td style="text-align:left;">低（單顆 MOSFET）</td><td style="text-align:left;">高（整合模組）</td><td style="text-align:left;">提升 3-5 倍</td></tr><tr><td style="text-align:left;"><strong>效率</strong></td><td style="text-align:left;">各級獨立優化</td><td style="text-align:left;">整體優化</td><td style="text-align:left;">提升 2-5%</td></tr></tbody></table><hr><h2 id="_4-關稅戰與地緣政治影響" tabindex="-1">4. 關稅戰與地緣政治影響 <a class="header-anchor" href="#_4-關稅戰與地緣政治影響" aria-label="Permalink to &quot;4. 關稅戰與地緣政治影響&quot;">​</a></h2><h3 id="中國-mosfet-產能擴張-→-低價競爭壓力" tabindex="-1">中國 MOSFET 產能擴張 → 低價競爭壓力 <a class="header-anchor" href="#中國-mosfet-產能擴張-→-低價競爭壓力" aria-label="Permalink to &quot;中國 MOSFET 產能擴張 → 低價競爭壓力&quot;">​</a></h3><ul><li>大陸功率元件廠（華潤微、士蘭微、三安光電等）大量擴產中</li><li>低價競爭壓力持續，尤其在低壓 MOSFET 領域</li><li><strong>台廠應對策略</strong>：轉向車用、工控高階市場避開紅海</li></ul><h3 id="安世半導體-nexperia-客戶轉單-→-台廠受惠" tabindex="-1">安世半導體（Nexperia）客戶轉單 → 台廠受惠 <a class="header-anchor" href="#安世半導體-nexperia-客戶轉單-→-台廠受惠" aria-label="Permalink to &quot;安世半導體（Nexperia）客戶轉單 → 台廠受惠&quot;">​</a></h3><ul><li>Nexperia（原飛思卡爾功率部門，現中資持有）地緣政治風險升高</li><li>全球車廠/工業客戶建立在地供應鏈 → <strong>台廠成為主要受益者</strong></li><li>強茂、台半等台廠直接受惠於轉單效應</li></ul><h3 id="china-1-供應鏈布局" tabindex="-1">China+1 供應鏈布局 <a class="header-anchor" href="#china-1-供應鏈布局" aria-label="Permalink to &quot;China+1 供應鏈布局&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">台廠</th><th style="text-align:left;">海外佈局</th><th style="text-align:left;">目的</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>強茂</strong></td><td style="text-align:left;">越南 TOREX (95%股權) + 菲律賓封裝線</td><td style="text-align:left;">中國—台灣—東南亞製造網絡</td></tr><tr><td style="text-align:left;"><strong>台半</strong></td><td style="text-align:left;">海外客戶多元化</td><td style="text-align:left;">降低地緣風險</td></tr><tr><td style="text-align:left;"><strong>富鼎</strong></td><td style="text-align:left;">海外客戶拓展中</td><td style="text-align:left;">車用/工控多元化</td></tr></tbody></table><hr><h2 id="_5-關鍵風險評估" tabindex="-1">5. 關鍵風險評估 <a class="header-anchor" href="#_5-關鍵風險評估" aria-label="Permalink to &quot;5. 關鍵風險評估&quot;">​</a></h2><h3 id="⚠️-景氣循環風險" tabindex="-1">⚠️ 景氣循環風險 <a class="header-anchor" href="#⚠️-景氣循環風險" aria-label="Permalink to &quot;⚠️ 景氣循環風險&quot;">​</a></h3><ul><li>MOSFET 2022-2023 經歷嚴重庫存調整（全球缺貨→過產→去庫存的完整週期）</li><li>若 AI 需求放緩或 EV 增速減慢，可能引發新一輪庫存調整</li><li><strong>當前狀態</strong>：2026 年結構性缺貨（交期 25-37 週），短期無去庫存壓力</li></ul><h3 id="⚠️-sic-良率挑戰" tabindex="-1">⚠️ SiC 良率挑戰 <a class="header-anchor" href="#⚠️-sic-良率挑戰" aria-label="Permalink to &quot;⚠️ SiC 良率挑戰&quot;">​</a></h3><ul><li>SiC 晶圓缺陷密度高，良率約 30-50%（vs. Si &gt;90%）</li><li>台廠 SiC 良率落後國際大廠（Wolfspeed、Infineon 達 60-70%）</li><li><strong>影響</strong>：SiC 產品毛利率可能低於預期，量產時程延後</li></ul><h3 id="⚠️-中國追趕" tabindex="-1">⚠️ 中國追趕 <a class="header-anchor" href="#⚠️-中國追趕" aria-label="Permalink to &quot;⚠️ 中國追趕&quot;">​</a></h3><ul><li>SiC 6 吋產能大量開出，天科合達、三安光電擴產積極</li><li>大陸 MOSFET 廠低價競爭，尤其在低壓領域</li><li><strong>台廠應對</strong>：轉向高階市場（車用、AI 伺服器）、提升技術門檻</li></ul><h3 id="⚠️-替代技術威脅" tabindex="-1">⚠️ 替代技術威脅 <a class="header-anchor" href="#⚠️-替代技術威脅" aria-label="Permalink to &quot;⚠️ 替代技術威脅&quot;">​</a></h3><ul><li><strong>GaN</strong>：在高頻充電領域（&lt;650V）蠶食 SiC/Si MOSFET 市場 <ul><li>GaN 功率半導體市場 2026 ~$26.5 億，CAGR 快速成長</li></ul></li><li><strong>先進 Si</strong>：Super Junction MOSFET 持續改進，低壓領域仍具成本優勢</li></ul><h3 id="⚠️-原材料與製造限制" tabindex="-1">⚠️ 原材料與製造限制 <a class="header-anchor" href="#⚠️-原材料與製造限制" aria-label="Permalink to &quot;⚠️ 原材料與製造限制&quot;">​</a></h3><ul><li>銅、環氧樹脂等原材料價格上漲（強茂已調漲 10-15%）</li><li>全球功率半導體 fab 產能已滿，新 fab 建置需 2-3 年</li><li>短期內供需緊張態勢難以緩解</li></ul><hr><h2 id="_6-2026-年關鍵結論" tabindex="-1">6. 2026 年關鍵結論 <a class="header-anchor" href="#_6-2026-年關鍵結論" aria-label="Permalink to &quot;6. 2026 年關鍵結論&quot;">​</a></h2><h3 id="✅-利多因素" tabindex="-1">✅ 利多因素 <a class="header-anchor" href="#✅-利多因素" aria-label="Permalink to &quot;✅ 利多因素&quot;">​</a></h3><ol><li><strong>AI 伺服器爆發</strong>：MOSFET 用量 3-6 倍增長，SPS 整合提高單價</li><li><strong>800V EV 普及</strong>：SiC 滲透率從低個位數朝雙位數邁進</li><li><strong>結構性缺貨</strong>：MOSFET 交期 25-37 週，SiC 汽車級 &gt;52 週</li><li><strong>China+1 轉單</strong>：台廠成為 Nexperia 客戶主要替代供應商</li><li><strong>漲價潮</strong>：全球功率元件普遍漲價 10-20%，台廠毛利率改善</li></ol><h3 id="⚠️-風險因素" tabindex="-1">⚠️ 風險因素 <a class="header-anchor" href="#⚠️-風險因素" aria-label="Permalink to &quot;⚠️ 風險因素&quot;">​</a></h3><ol><li><strong>景氣循環</strong>：歷史週期性波動仍存，若 AI/EV 需求放緩可能影響</li><li><strong>SiC 良率</strong>：台廠 SiC 良率落後國際大廠</li><li><strong>中國追趕</strong>：SiC/MOSFET 大量擴產，低價競爭</li><li><strong>GaN 替代</strong>：高頻充電領域 GaN 蠶食 SiC/Si MOSFET</li><li><strong>地緣政治</strong>：中美貿易摩擦持續，供應鏈布局壓力</li></ol><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li><strong>GM Insights</strong> (2026-05): 功率半導體市場, Infineon 市佔 ~19.5%, Top 5 合計 ~50-55%</li><li><strong>IntelMarketResearch</strong> (2026-05): N-Channel Power MOSFET 市場, Infineon ~18%, ST+ON &gt;45%</li><li><strong>Baird / Investing.com</strong> (2026-05): MOSFET 交期數據, 結構性缺貨持續至 H2 2026</li><li><strong>Chipapex</strong> (2026-05): 全球功率半導體缺貨, 交期拉長至 30 週+</li><li><strong>TrendForce</strong> (2026-01): 全球半導體市場分析, AI 驅動功率元件需求</li><li><strong>Manufacturing Dive / Omdia</strong> (2026-05): AI 半導體晶片短缺分析</li><li><strong>Fortune Business Insights</strong> (2026-05): 汽車級 SiC ~$82.4億→$319億</li><li><strong>Mordor Intelligence</strong> (2026-05): SiC 功率半導體市場 ~$34億, GaN ~$26.5億</li><li><strong>DataMintelligence</strong> (2026-05): 功率半導體市場 ~$58.8億, SiC CAGR 24.7-35%</li><li><strong>GII</strong> (2026-05): Power MOSFET ~$98.1億, CAGR 6.3%</li><li><strong>工商時報</strong> (2026-03): 強茂法說 — AI 佔比 9-12%, 交期 30 週</li><li><strong>鉅亨網</strong> (2026-05): 台半法說 — NVIDIA Rubin, SiC 1200V</li><li><strong>CMoney</strong> (2026-05): 力智、富鼎最新動態</li><li><strong>Vocus / 經濟日報</strong> (2026-05): 富鼎、茂矽、尼克森、杰力法說會</li></ol>`,51)])])}const x=e(s,[["render",i]]);export{c as __pageData,x as default};
